import React, { useState } from "react";
import axios from "axios";
import Api from "../api/Api";
import {
  useLocation,
  useNavigate,
} from "react-router-dom";

function VerifyOtp() {
  const [otp, setOtp] = useState("");

  const location = useLocation();
  const navigate = useNavigate();

  const mobile = location.state?.mobile;

  const handleVerify = async (e) => {
    e.preventDefault();

    try {
      const res = await axios.post(
        Api.verify_otp,
        {
          mobile,
          otp,
        }
      );

      localStorage.setItem(
        "token",
        res.data.token
      );

      localStorage.setItem(
        "role",
        res.data.role
      );

      alert("Login Successful");

      if (res.data.role === "admin") {
        navigate("/admin");
      } else if (
        res.data.role === "driver"
      ) {
        navigate("/driver");
      } else {
        navigate("/supervisor");
      }
    } catch (err) {
      alert(
        err.response?.data?.message ||
          "OTP Verification Failed"
      );
    }
  };

  if (!mobile) {
    return (
      <div className="min-h-screen flex justify-center items-center bg-gray-100">
        <div className="bg-white p-6 rounded-xl shadow-lg">
          <h2 className="text-red-600 font-semibold text-lg">
            Invalid Access
          </h2>
          <p className="text-gray-500 mt-2">
            Please login again.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 flex items-center justify-center px-4">
      <div className="bg-white shadow-lg rounded-xl p-8 w-full max-w-md">

        {/* Vehicle Image */}
        <div className="flex justify-center mb-4">
          <img
            src="/garbageVehicle.jpeg"
            alt="Garbage Vehicle"
            className="w-24 h-24"
          />
        </div>

        {/* Heading */}
        <h1 className="text-3xl font-bold text-center text-green-700">
          GarbagePickUpVehicle
        </h1>

        <p className="text-center text-gray-500 mt-2">
          OTP Verification
        </p>

        <div className="bg-green-50 border border-green-200 rounded-lg p-3 mt-4 mb-6">
          <p className="text-center text-green-700 text-sm">
            OTP sent to
          </p>

          <p className="text-center font-semibold text-gray-800">
            +91 {mobile}
          </p>
        </div>

        {/* Form */}
        <form
          onSubmit={handleVerify}
          className="space-y-4"
        >
          <div>
            <label className="block text-sm font-medium mb-1">
              Enter OTP
            </label>

            <input
              type="text"
              maxLength="6"
              value={otp}
              onChange={(e) =>
                setOtp(e.target.value)
              }
              placeholder="Enter 6 Digit OTP"
              className="w-full border rounded-lg px-4 py-2 text-center tracking-widest text-lg focus:outline-none focus:ring-2 focus:ring-green-500"
              required
            />
          </div>

          <button
            type="submit"
            className="w-full bg-green-600 text-white py-2 rounded-lg font-semibold hover:bg-green-700 transition"
          >
            Verify OTP
          </button>
        </form>
      </div>
    </div>
  );
}

export default VerifyOtp;
